		if err != nil {
			return nil, err
		}
		return pg, nil
	}
	return nil, err
}

func (cc *jobcontroller) generateRelatedPodGroupName(job *batch.Job) string {
	return fmt.Sprintf("%s-%s", job.Name, string(job.UID))
}

