568	func getPodGroupPhase(jobInfo *api.JobInfo, unschedulable bool) scheduling.PodGroupPhase {
569		// If running tasks && unschedulable, unknown phase
570		if len(jobInfo.TaskStatusIndex[api.Running]) != 0 && unschedulable {
571			return scheduling.PodGroupUnknown
572		}
573	
574		scheduled := 0
575		completed := 0
576		for s, tasks := range jobInfo.TaskStatusIndex {
577			if api.ScheduledStatus(s) {
578				scheduled += len(tasks)
579			}
580			if api.CompletedStatus(s) {
581				completed += len(tasks)
582			}
583		}
584	
585		if int32(scheduled) >= jobInfo.PodGroup.Spec.MinMember {
586			// If all scheduled tasks are completed, then the podgroup is completed
587			if scheduled == completed {
588				return scheduling.PodGroupCompleted
589			}
590			return scheduling.PodGroupRunning
591		}
592	
593		if jobInfo.PodGroup.Status.Phase != scheduling.PodGroupInqueue {
594			return scheduling.PodGroupPending
595		}
596	
