387	// Bind will add silo cluster annotation on pod and podgroup
388	func (pgb *podgroupBinder) Bind(job *schedulingapi.JobInfo, cluster string) (*schedulingapi.JobInfo, error) {
389		if len(job.Tasks) == 0 {
390			klog.V(4).Infof("Job pods have not been created yet")
391			return job, nil
392		}
393		for _, task := range job.Tasks {
394			pod := task.Pod
395			pod.Annotations[batch.ForwardClusterKey] = cluster
396			pod.ResourceVersion = ""
397			_, err := pgb.kubeclient.CoreV1().Pods(pod.Namespace).UpdateStatus(context.TODO(), pod, metav1.UpdateOptions{})
398			if err != nil {
399				klog.Errorf("Error while update pod annotation with error: %v", err)
400				return nil, err
401			}
402		}
403	
404		pg := job.PodGroup
405		pg.Annotations[batch.ForwardClusterKey] = cluster
406		podgroup := &vcv1beta1.PodGroup{}
407		if err := schedulingscheme.Scheme.Convert(&pg.PodGroup, podgroup, nil); err != nil {
408			klog.Errorf("Error while converting PodGroup to v1alpha1.PodGroup with error: %v", err)
409			return nil, err
410		}
411		newPg, err := pgb.vcclient.SchedulingV1beta1().PodGroups(pg.Namespace).Update(context.TODO(), podgroup, metav1.UpdateOptions{})
412		if err != nil {
413			klog.Errorf("Error while update PodGroup annotation with error: %v", err)
414			return nil, err
415		}
416		job.PodGroup.ResourceVersion = newPg.ResourceVersion
417		klog.V(4).Infof("Bind PodGroup <%s> successfully", job.PodGroup.Name)
418		return job, nil
419	}
